[FormDataSourceEventHandler(formDataSourceStr(PurchAgreementCreate, PurchAgreementHeader), FormDataSourceEventType::Written)]
public static void PurchAgreementHeader_OnWritten(FormDataSource sender, FormDataSourceEventArgs e)
{
    ETG_PurchaseAgreementHeader purchaseAgreementHeaderTP;//   = sender.cursor();;
    FormDataSource              PurchAgreementHeader_ds   = sender.formRun().dataSource('PurchAgreementHeader');
    PurchAgreementHeader        purchAgreementHeader        =  PurchAgreementHeader_ds.cursor();//sender.cursor();
    FormDataSource              AgreementHeaderDefault_ds   = sender.formRun().dataSource('AgreementHeaderDefault');
    AgreementHeaderDefault      agreementHeaderDefault      = AgreementHeaderDefault_ds.cursor();


    purchaseAgreementHeaderTP.PurchAgreementId      = purchAgreementHeader.PurchNumberSequence;
    purchaseAgreementHeaderTP.SellerAccountNum      = purchAgreementHeader.VendAccount;
    purchaseAgreementHeaderTP.SellerDeliveryAddress = VendTable::find(purchAgreementHeader.VendAccount).postalAddress().RecId;
    purchaseAgreementHeaderTP.SellerBank            = VendTable::find(purchAgreementHeader.VendAccount).BankAccount;
    purchaseAgreementHeaderTP.BuyerAccountNum       = curExt();
    purchaseAgreementHeaderTP.BuyerDeliveryAddress  = CompanyInfo::findDataArea(curExt()).postalAddress().RecId;
    purchaseAgreementHeaderTP.BuyerBank             = CompanyInfo::findDataArea(curExt()).Bank;
    purchaseAgreementHeaderTP.TermPaymDescription   = PaymTerm::find(agreementHeaderDefault.PaymentTerms).Description;
    purchaseAgreementHeaderTP.TermsOfDelDescription = DlvTerm::find(agreementHeaderDefault.DeliveryTerm).Txt;
    purchaseAgreementHeaderTP.insert();
}

[FormControlEventHandler(formControlStr(PurchAgreement, BuyerDeliveryRef), FormControlEventType::Lookup)]
public static void  BuyerDeliveryRef_OnLookup(FormControl sender, FormControlEventArgs e)
{
    ETG_PurchAgreementHeaderHandlers::createLookup(sender);

    FormControlCancelableSuperEventArgs cancelableArgs = e as FormControlCancelableSuperEventArgs;
    cancelableArgs.CancelSuperCall();
}

private static void createLookup(FormReferenceGroupControl _ctrl)
{
    SysReferenceTableLookup     sysTableLookup  = SysReferenceTableLookup::newParameters(tablenum(LogisticsPostalAddress), _ctrl);
    Query                       lookupQuery = new Query();
    QueryBuildDataSource        lookupQry   = new QueryBuildDataSource();        
    SysReferenceTableLookup     sysRefTableLookup;
    QuerybuildDatasource        qbd, qbd1, qbd2;

    qbd     = lookupQuery.addDataSource(tablenum(LogisticsPostalAddress));
    qbd1    = qbd.addDataSource(tablenum(DirPartyLocation));
    qbd1.addLink(fieldNum(LogisticsPostalAddress, Location), fieldNum(DirPartyLocation, Location));
    qbd1.joinMode(JoinMode::InnerJoin);

    qbd2 = qbd1.addDataSource(tablenum(CompanyInfo));
    qbd2.addLink(fieldNum(DirPartyLocation, Party), (fieldNum(CompanyInfo, RecId)));
    qbd2.joinMode(JoinMode::InnerJoin);

    qbd2.addRange(fieldnum(CompanyInfo, DataArea)).value(SysQuery::value(curext()));

    sysTableLookup.addLookupfield(fieldNum(LogisticsPostalAddress, Location));
    sysTableLookup.addLookupfield(fieldNum(LogisticsPostalAddress, Street));

    sysTableLookup.parmQuery(lookupQuery);
    sysTableLookup.performFormLookup();
}

[FormControlEventHandler(formControlStr(PurchAgreement, ButtonSalesAgreementTP), FormControlEventType::Clicked)]
public static void ButtonSalesAgreementTP_OnClicked(FormControl sender, FormControlEventArgs e)
{
    SalesAgreementHeader        salesAgreementHeader;
    FormButtonControl callerButton = sender as FormButtonControl;
    FormDataSource formDS          = sender.formRun().dataSource('PurchAgreementHeader');
    PurchAgreementHeader     purchAgreementHeader      = formDS.cursor();

    MenuFunction menuFunction = new MenuFunction(menuitemdisplaystr(SalesAgreement), MenuItemType::Display);
    Args args  = new Args();
    salesAgreementHeader = SalesAgreementHeader::findAgreementId(purchAgreementHeader.ETG_SalesAgreementIdTP);
    args.record(salesAgreementHeader);
    menuFunction.run(args);

}

[FormControlEventHandler(formControlStr(PurchAgreement, SellerDeliveryRef), FormControlEventType::Lookup)]
public static void  SellerDeliveryRef_OnLookup(FormControl sender, FormControlEventArgs e)
{
