    /// <summary>
    ///
    /// </summary>
    /// <param name="sender"></param>
    /// <param name="e"></param>
    [FormControlEventHandler(formControlStr(PurchAgreement, Notifytodifferentparty), FormControlEventType::Modified)]
    public static void Notifytodifferentparty_OnModified(FormControl sender, FormControlEventArgs e)
    {
        ETG_PurchaseAgreementHeader purchaseAgreementHeaderETG = sender.formRun().dataSource().cursor();
        FormRun             element       = sender.formRun(); //form element
        FormControl         NotifyName   = element.design(0).controlName('NotifyName');
        FormControl         NotifyAddress   = element.design(0).controlName('NotifyAddress');

        if(purchaseAgreementHeaderETG.Notifytodifferentparty == NoYes::Yes)// && purchaseAgreementHeaderETG.Consignee && purchaseAgreementHeaderETG.OnAccountOf)
       {
                 NotifyName.enabled(true);
                 NotifyAddress.enabled(true);
       }
       else if(purchaseAgreementHeaderETG.Notifytodifferentparty == NoYes::No) //&& purchaseAgreementHeaderETG.Consignee && purchaseAgreementHeaderETG.OnAccountOf)
        {
            purchaseAgreementHeaderETG.Name     = '';
            purchaseAgreementHeaderETG.Address  = '';
                 NotifyName.enabled(false);
                 NotifyAddress.enabled(false);
        }
    }

/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(PurchAgreement, Futures), FormControlEventType::Modified)]
public static void Futures_OnModified(FormControl sender, FormControlEventArgs e)
{
    FormRun             element         = sender.formRun();
    FormCheckBoxControl Futures         = element.design(0).controlName("Futures");
    FormControl         PricingMonth    = element.design(0).controlName('PricingMonth');
    FormControl         Pricingfromdate = element.design(0).controlName('Pricingfromdate');
    FormControl         Pricingtodate   = element.design(0).controlName('Pricingtodate');
    FormControl         AdvancedueForm  = element.design(0).controlName('AdvancedueForm');

    PricingMonth.enabled(Futures.value() == 1);
    Pricingfromdate.enabled(Futures.value() == 1);
    Pricingtodate.enabled(Futures.value() == 1);
    AdvancedueForm.enabled(Futures.value() == 1);
}

/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormDataSourceEventHandler(formDataSourceStr(PurchAgreement, ETG_PurchaseAgreementHeader), FormDataSourceEventType::Activated)]
public static void ETG_PurchaseAgreementHeader_OnActivated(FormDataSource sender, FormDataSourceEventArgs e)
{
    FormDataSource ETG_PurchaseAgreementHeader_ds   = sender;
    FormRun             element                 = sender.formRun();
    FormCheckBoxControl Futures                 = element.design(0).controlName("Futures");
    FormControl         PricingMonth            = element.design(0).controlName('PricingMonth');
    FormControl         Pricingfromdate         = element.design(0).controlName('Pricingfromdate');
    FormControl         Pricingtodate           = element.design(0).controlName('Pricingtodate');
    FormControl         AdvancedueForm          = element.design(0).controlName('AdvancedueForm');
    ETG_PurchaseAgreementHeader          purchaseAgreementHeader = ETG_PurchaseAgreementHeader_ds.cursor();

    PricingMonth.enabled(Futures.value() == 1);
    Pricingfromdate.enabled(Futures.value() == 1);
    Pricingtodate.enabled(Futures.value() == 1);
    AdvancedueForm.enabled(Futures.value() == 1);

    if (purchaseAgreementHeader.BuyerSecondaryBank == '' || purchaseAgreementHeader.BuyerBank == '')
    {
