[FormControlEventHandler(formControlStr(PurchAgreement, ShipmentTabPage), FormControlEventType::PageActivated)]
public static void ShipmentTabPage_OnPageActivated(FormControl sender, FormControlEventArgs e)
{
    ETG_PurchaseAgreementHeader purchaseAgreementHeaderETG = sender.formRun().dataSource().cursor();
    FormRun             element       = sender.formRun(); //form element
    FormControl         NotifyName    = element.design(0).controlName('NotifyName');
    FormControl         NotifyAddress = element.design(0).controlName("NotifyAddress");

    if(purchaseAgreementHeaderETG.Notifytodifferentparty == NoYes::Yes)// && purchaseAgreementHeaderETG.Consignee && purchaseAgreementHeaderETG.OnAccountOf)
    {
        NotifyName.enabled(true);
        NotifyAddress.enabled(true);
    }
    else if(purchaseAgreementHeaderETG.Notifytodifferentparty == NoYes::No) //&& purchaseAgreementHeaderETG.Consignee && purchaseAgreementHeaderETG.OnAccountOf)
    {
        purchaseAgreementHeaderETG.Name = "";
        purchaseAgreementHeaderETG.Address = "";
        NotifyName.enabled(false);
        NotifyAddress.enabled(false);
    }
}

