///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormDataSourceEventHandler(formDataSourceStr(PurchAgreement, PurchLine), FormDataSourceEventType::QueryExecuting)]
public static void PurchLine_OnQueryExecuting(FormDataSource sender, FormDataSourceEventArgs e)
{
    AgreementLine agreementLine = sender.formRun().dataSource(FormDataSourcestr(PurchAgreement, ALine)).cursor();

    // Ranges added to retrieve only the purchAgreement related purchLine records.
    if (agreementLine.RecId)
    {
        sender.query().dataSourceTable(tableNum(PurchLine)).addRange(fieldNum(PurchLine, MatchingAgreementLine)).value(queryValue(agreementLine.RecId));
    }
    else
    {
        sender.query().dataSourceTable(tableNum(PurchLine)).addRange(fieldNum(PurchLine, RecId)).value(queryValue(0));
    }

}

