/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(PurchAgreement, SellerBankString), FormControlEventType::Lookup)]
public static void SellerBankString_OnLookup(FormControl sender, FormControlEventArgs e)
{
    if(curExt() == "O001")
    {
        FormRun                 formRun;
        FormDataSource          purchAgreementHeaderDS;
        PurchAgreementHeader    purchAgreementHeader;
        SysTableLookup          sysTableLookup;
        Query                   query;
        QueryBuildDataSource    qbds;

        formRun = sender.formRun();

        purchAgreementHeaderDS = formRun.dataSource(formDataSourceStr(PurchAgreement, PurchAgreementHeader)) as FormDataSource;

        purchAgreementHeader = purchAgreementHeaderDS.cursor();

        query = new Query();
        qbds = query.addDataSource(tableNum(VendBankAccount));

        qbds.addRange(fieldNum(VendBankAccount, VendAccount)).value(queryValue(purchAgreementHeader.VendAccount));

        sysTableLookup = SysTableLookup::newParameters(tableNum(VendBankAccount),sender);

        sysTableLookup.addLookupField(fieldNum(VendBankAccount, AccountID));
        sysTableLookup.addLookupField(fieldNum(VendBankAccount, AccountNum));

        sysTableLookup.parmQuery(query);
        sysTableLookup.performFormLookup();

        FormControlCancelableSuperEventArgs cancelableArgs = e as FormControlCancelableSuperEventArgs;
        cancelableArgs.CancelSuperCall();
    }
}

